var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"글쎄? 어떡할까?","JPN":"さあ、どうしましょう。","ENG":"Well, what should I do?","TWN":"這個嘛，我想想吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"무슨 말이죠?","JPN":"どういうことですか？","ENG":"Pardon?","TWN":"妳什麼意思？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"다 들통난 마당에 질척거리긴 싫지만, 그래도 이렇게 끝내기는 섭섭하잖아?","JPN":"全部バレてしまったところで引き延ばすのは気が引けるけど。\\nこのまま終わらせるのも名残惜しいでしょう？","ENG":"I hate to be a sore loser, but I don't want to end things like this, either.","TWN":"既然被發現了，我也不想再拖下去，不過就此結束，未免也有點太可惜了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"정체가 드러난 범인은 원래 최후의 발악을 하기 마련 아니겠어?","JPN":"正体がバレた犯人は最後の悪あがきをするのが定番だしね。","ENG":"The perpetrator always makes a last-ditch effort before it's over, doesn't it?","TWN":"原形畢露的兇手，不得做一做最後的掙扎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"설마 싸울 셈이야? 이쪽은 두 명이고 그쪽은 한 명이잖아?","JPN":"まさか、戦うつもり？　こっちは二人でそっちは一人よ？","ENG":"Wait, do you want to fight? There are two of us, and you're alone.","TWN":"妳想打架？我們可是兩個人，而妳只有妳一個。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"후훗, 정말 그렇다고 생각해?","JPN":"ふふっ、本当にそう思うの？","ENG":"Hah hah. You think so?","TWN":"哼哼，妳真的那麼想？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"무슨 의미죠?","JPN":"どういう意味ですか？","ENG":"What does that mean?","TWN":"什麼意思？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"내가 범인인지 알아맞춘 건 칭찬해 줄게.","JPN":"私が犯人だって暴いたことは褒めてあげるわ。","ENG":"I commend you for finding me.","TWN":"能猜出我是兇手，確實值得誇讚。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 어떻게 범행을 저질렀는지는 아직 모르잖아?","JPN":"でもどうやって犯行に及んだかは、まだ知らないでしょう？","ENG":"But you still don't know how I did it.","TWN":"不過妳們還不知道我是如何犯下罪行的吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"나 혼자 그 쟁쟁한 실력자들을 어떻게 희생자로 만들었겠어.","JPN":"私一人で、あの実力者たちを犠牲者にできたと思う？","ENG":"How do you think I dominated such strong Counters on my own?","TWN":"我自己一個人怎麼可能把那些高手都變成受害者。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그러고 보니, 카일은 그렇다 쳐도 버터맨은 누가 습격한다고 쉽게 당할 녀석이 아닌데......?","JPN":"そういえばカイルはいいとしても、バターマンはそう簡単にやられるやつじゃない……","ENG":"Now that you mention it, Kyle may have been easy to dominate, but not Sleazeball.","TWN":"是啊，凱爾就算了，油膩男可不是能輕易襲擊的人啊……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"바로 이런 방식이지.","JPN":"見せてあげるわ。","ENG":"Like this.","TWN":"我用的就是這種方式。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_XMAS_NULL","text":{"KOREA":"성야의 저주가 다가온다!","JPN":"聖夜の呪いがやってくる！","ENG":"The Curse of the Holy Night is coming!","TWN":"耶誕的詛咒來了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG"},{"id":"L30_1","type":"dialog","speaker":"SHIELD_ADMIN_XMAS_NULL","text":{"KOREA":"성야의 저주를 받아들여라!","JPN":"聖夜の呪いを受け入れろ！","ENG":"Embrace the Curse of the Holy Night!","TWN":"接受耶誕的詛咒吧！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_XMAS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG"},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐야?! 조각상이 움직이고 있잖아......!","JPN":"何！？　彫刻像が動いてる……！","ENG":"Huh? The sculptures are moving!","TWN":"什麼？！雕像動起來了……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그것뿐만이 아니에요. 이 방 안의 공간 자체가 변이하고 있어요.","JPN":"それだけじゃありません。この部屋の空間が歪んでいます。","ENG":"Not only that. This space, the room itself, is changing.","TWN":"不止如此，這房裡的空間也在變異。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이건 아무리 봐도...... 고심도 이면세계에서나 나타나는 현상이에요.","JPN":"これはどう見ても……高深度の裏世界で起こる現象です。","ENG":"I've only seen things like this happening on the hyperdepth of the Counterside.","TWN":"這怎麼看……都是高深度異界裡才會有的現象。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이면세계라고? 하지만 워치에는 아무런 반응도 없었는데?","JPN":"裏世界？　でもウォッチが反応してないわよ？","ENG":"The Counterside? But my Watch has been quiet!","TWN":"異界？可是能量環沒有任何反應啊？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아마 이면세계와 유사하게 형성된 특이한 공간인 것 같아요.","JPN":"おそらく裏世界と似た特異空間だと思います。","ENG":"This must be a special space, created to simulate the Counterside.","TWN":"應該是和異界相似的特殊空間。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨도 산장에 올 때 뭔가 이상한 느낌 들지 않았어요?","JPN":"シルビアさんも山荘に来るとき、何かおかしいと感じませんでしたか？","ENG":"Sylvia, didn't you feel strange when you came up to this cabin?","TWN":"希爾維亞，妳來山莊的時候不也覺得很奇怪嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"으음. 지도에도 안 나와서 초대장에 있던 괴상한 길로 빙글빙글 돌아오긴 했지.","JPN":"う～ん。確かに地図にも載ってないし、招待状にあったヘンな道をぐるぐる回って来たけど。","ENG":"Mm... It didn't show on the map, so I had to follow the strangely winding road shown on the invitation.","TWN":"嗯，在地圖上找不到山莊，所以跟著邀請函上奇怪的路走了許久才到的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그래요. 처음부터 여긴 성야의 살인마가 준비해 둔 사냥터였던 거에요.","JPN":"そうです。最初からここは聖夜の殺人鬼が用意した狩り場だったんです。","ENG":"Yes. This place has been set up to be the Killer's hunting ground.","TWN":"是的，這裡一開始就是耶誕的嫌疑犯準備的獵場。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아니, 너네 사장은 그런 곳에 사람을 초대한 거야? 연말에 뭐 이런 법이 다 있어?!","JPN":"てことは、あんたの社長はそんなところに人を招待したわけ？\\n年末のハッピーな日に！？","ENG":"What? And your boss invited us here? What a great way to end the year!","TWN":"你們老闆怎麼把人邀請到這種地方？都年末了還這樣？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"저희 사장님 취향이 독특하긴 하죠. 그건 저도 할 말이 없네요.","JPN":"社長が少し変わっているのは、さすがに私も否定できません。","ENG":"My boss has unique taste. I can't refute that.","TWN":"我們老闆的興趣向來特殊，對此我也無話可說。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"자, 성야의 클라이맥스야. 명탐정 여러분.","JPN":"さぁ、聖夜のクライマックスよ。名探偵さん。","ENG":"Alright, detectives, we've reached the height of the Holy Night.","TWN":"耶誕的高潮即將要到來了，各位名偵探。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"날 쓰러트리고 해피엔딩을 맞이할 수 있으려나?","JPN":"私を倒してハッピーエンドを迎えられるかしら？","ENG":"Maybe you would have a happy ending if you beat me.","TWN":"能否打敗我迎來幸福的結局呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이거 딱 봐도 승산이 없잖아. 숫자가 너무 많아.","JPN":"こんなの勝算がない。すでに数で負けてるわ！","ENG":"I can already tell we're doomed. There are way too many of them.","TWN":"這根本就沒有勝算，人太多了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이렇게 된 이상 그 바보 같은 X자라도 예쁘게 그려 주길 바라는 수밖에 없겠는데.","JPN":"こうなった以上、あのバカみたいなX印を綺麗に書いて欲しいって頼もうかしら。","ENG":"I just hope the ridiculous X on my forehead won't make me look too ugly.","TWN":"既然都這樣了，就只能希望她能給我畫一個好看的X了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......아직이에요. 제게 이 난관을 타개할 좋은 방법이 있거든요.","JPN":"……まだ終わりではありません。この難局を打開できるいい方法があります。","ENG":"Don't give up hope, just yet. I've got an idea.","TWN":"……還沒結束，我有一個好辦法可以攻破這個難關。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"좋은 방법?","JPN":"いい方法？","ENG":"You've got an idea?","TWN":"好辦法？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네. 그러려면 먼저 사장님을 찾아야 돼요.","JPN":"はい。まずは社長を探さなければなりません。","ENG":"Yes, and I need the Boss for that.","TWN":"是的，我們需要先找到老闆。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러니까 일단 달려요!","JPN":"だから、ひとまず走りましょう！","ENG":"So, let's run for now!","TWN":"總之先跑吧！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그냥 걸어서 좀 가면 좋겠다, 진짜!","JPN":"あぁ、もう！　走るのは勘弁してよ！","ENG":"Can't we just walk? Geez!","TWN":"我真希望可以用走的，真的！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};